success_message:
✅  Project '{{.project_name}}' created successfully!

Deploy in order:
{{- if eq .include_retriever "yes"}}
  cd retriever
  databricks bundle deploy -t dev
  databricks bundle run data_prep_job -t dev
  databricks bundle run vector_search_job -t dev
{{- end}}
{{- if eq .include_tools "yes"}}
  cd ../tools
  databricks bundle deploy -t dev
  databricks bundle run deploy_uc_functions_job -t dev
{{- end}}
{{- if eq .include_agent "yes"}}
  cd ../agent
  databricks bundle deploy -t dev
  databricks bundle run agent_development_job -t dev
{{- end}}
{{- if eq .include_evaluation "yes"}}
  cd ../evaluation
  databricks bundle deploy -t dev
{{- end}}

